/* eslint-disable @next/next/no-img-element */
"use client";

import { ShoppingCart } from "lucide-react";
import Link from "next/link";

import { useStorefront } from "@/components/providers/StorefrontProvider";
import { formatIQD, getProductName } from "@/lib/storefront";
import type { Product } from "@/lib/types";
import { useCartStore } from "@/store/cart";

type ProductCardProps = {
  product: Product;
};

export function ProductCard({ product }: ProductCardProps) {
  const addItem = useCartStore((state) => state.addItem);
  const { language, isRTL } = useStorefront();
  const hasDiscount =
    typeof product.original_price === "number" &&
    product.original_price > product.price_iqd;
  const discountPercent = hasDiscount
    ? Math.round(
        (((product.original_price ?? product.price_iqd) - product.price_iqd) /
          (product.original_price ?? product.price_iqd)) *
          100
      )
    : 0;

  return (
    <article className="group overflow-hidden rounded-[2.5rem] bg-white shadow-soft transition duration-300 hover:-translate-y-1 hover:shadow-premium">
      <Link href={`/product/${product.id}`} className="block">
        <div className="relative aspect-[4/4.7] overflow-hidden bg-slate-50">
          <div className="flex h-[60%] items-center justify-center px-8 pt-8">
            <img
              src={product.image_url}
              alt={getProductName(product, language)}
              className="h-full w-full object-contain transition duration-500 group-hover:scale-105"
              loading="lazy"
            />
          </div>

          {hasDiscount ? (
            <span
              className={`absolute top-5 rounded-full bg-[#1D1D1F] px-3 py-1.5 text-xs font-semibold text-white ${
                isRTL ? "right-5" : "left-5"
              }`}
            >
              {language === "ar" ? `خصم ${discountPercent}%` : `${discountPercent}% off`}
            </span>
          ) : null}
        </div>
      </Link>

      <div className="space-y-4 px-6 pb-6 pt-2">
        <div className={isRTL ? "text-right" : "text-left"}>
          <Link
            href={`/product/${product.id}`}
            className="line-clamp-2 text-lg font-semibold tracking-tight text-[#1D1D1F]"
          >
            {getProductName(product, language)}
          </Link>
          <p className="mt-3 text-xs uppercase tracking-[0.28em] text-slate-400">
            {product.stock_quantity > 0
              ? language === "ar"
                ? "متوفر"
                : "In stock"
              : language === "ar"
                ? "نفد"
                : "Out"}
          </p>
        </div>

        <div
          className={`flex items-end justify-between gap-3 ${
            isRTL ? "flex-row-reverse" : ""
          }`}
        >
          <div className={isRTL ? "text-right" : "text-left"}>
            <p className="text-xl font-semibold text-[#1D1D1F]">
              {formatIQD(product.price_iqd, language)}
            </p>
            {hasDiscount ? (
              <p className="mt-1 text-sm text-slate-400 line-through">
                {formatIQD(product.original_price ?? product.price_iqd, language)}
              </p>
            ) : null}
          </div>

          <button
            type="button"
            onClick={() => addItem(product)}
            disabled={product.stock_quantity <= 0}
            className={`inline-flex min-h-12 items-center justify-center gap-2 rounded-full px-5 py-3 text-sm font-semibold transition ${
              product.stock_quantity > 0
                ? "bg-primary text-white shadow-button hover:-translate-y-0.5 hover:shadow-premium"
                : "cursor-not-allowed bg-slate-200 text-slate-500"
            }`}
          >
            <ShoppingCart size={16} />
            <span>{language === "ar" ? "أضف" : "Add"}</span>
          </button>
        </div>
      </div>
    </article>
  );
}
